import { Navbar, Container, Heading } from '@nextui-org/react';

const Header = () => {
  return (
    <Navbar shadow>
      <Container>
        <Heading>¡Bienvenido a mi portafolio!</Heading>
      </Container>
    </Navbar>
  );
};

export default Header;
